package com.example.shoppingapp.database;

import android.content.Context;

import androidx.annotation.NonNull;
import androidx.room.Database;
import androidx.room.Room;
import androidx.room.RoomDatabase;
import androidx.sqlite.db.SupportSQLiteDatabase;

import com.example.shoppingapp.database.dao.CategoryDao;
import com.example.shoppingapp.database.dao.FavoriteDao;
import com.example.shoppingapp.database.dao.OrderDao;
import com.example.shoppingapp.database.dao.OrderDetailDao;
import com.example.shoppingapp.database.dao.ProductDao;
import com.example.shoppingapp.database.dao.ReviewDao;
import com.example.shoppingapp.database.dao.UserDao;
import com.example.shoppingapp.database.entity.Category;
import com.example.shoppingapp.database.entity.Favorite;
import com.example.shoppingapp.database.entity.Order;
import com.example.shoppingapp.database.entity.OrderDetail;
import com.example.shoppingapp.database.entity.Product;
import com.example.shoppingapp.database.entity.Review;
import com.example.shoppingapp.database.entity.User;

import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;

@Database(entities = {User.class, Category.class, Product.class, Order.class, OrderDetail.class, Favorite.class, Review.class}, version = 14, exportSchema = false)
public abstract class AppDatabase extends RoomDatabase {

    public abstract UserDao userDao();
    public abstract CategoryDao categoryDao();
    public abstract ProductDao productDao();
    public abstract OrderDao orderDao();
    public abstract OrderDetailDao orderDetailDao();
    public abstract FavoriteDao favoriteDao();
    public abstract ReviewDao reviewDao();

    private static volatile AppDatabase INSTANCE;
    public static final ExecutorService databaseExecutor = Executors.newFixedThreadPool(4);

    public static AppDatabase getInstance(Context context) {
        if (INSTANCE == null) {
            synchronized (AppDatabase.class) {
                if (INSTANCE == null) {
                    INSTANCE = Room.databaseBuilder(
                                    context.getApplicationContext(),
                                    AppDatabase.class,
                                    "shopping_db")
                            .fallbackToDestructiveMigration(true)
                            .addCallback(new SeedCallback())
                            .build();
                }
            }
        }
        return INSTANCE;
    }

    private static class SeedCallback extends Callback {
        @Override
        public void onCreate(@NonNull SupportSQLiteDatabase db) {
            super.onCreate(db);
            seedData();
        }

        @Override
        public void onDestructiveMigration(@NonNull SupportSQLiteDatabase db) {
            super.onDestructiveMigration(db);
            seedData();
        }

        private void seedData() {
            databaseExecutor.execute(() -> {
                AppDatabase database = INSTANCE;
                if (database == null) return;

                if (database.productDao().getProductCount() > 0) return;

                // === 1. Seed Categories (Chính xác 5 danh mục) ===
                CategoryDao categoryDao = database.categoryDao();
                categoryDao.insert(new Category("Trái cây nội địa", "Tươi ngon từ vùng miền VN", "https://images.unsplash.com/photo-1619566636858-adf3ef46400b?auto=format&fit=crop&w=500&q=60"));
                categoryDao.insert(new Category("Trái cây nhập khẩu", "Từ Mỹ, Úc, Nhật Bản", "https://images.unsplash.com/photo-1519996529931-28324d5a630e?auto=format&fit=crop&w=500&q=60"));
                categoryDao.insert(new Category("Trái cây sấy", "Đồ sấy khô tự nhiên", "https://images.unsplash.com/photo-1596591606975-97ee5cef3a1e?auto=format&fit=crop&w=500&q=60"));
                categoryDao.insert(new Category("Nước ép tươi", "Nguyên chất 100%", "data:image/jpeg;base64,"));
                categoryDao.insert(new Category("Giỏ quà tặng", "Sang trọng biếu tặng", "https://images.unsplash.com/photo-1543157145-f78c636d023d?auto=format&fit=crop&w=500&q=60"));

                // === 2. Seed Products (Chính xác 10 sản phẩm) ===
                ProductDao productDao = database.productDao();
                Product p;

                // Nội địa (Cat 1)
                p = new Product("Xoài Cát Hòa Lộc", "Tiền Giang", "Xoài loại 1, vị ngọt thanh, hương thơm đặc trưng.", 85000, "https://images.unsplash.com/photo-1553279768-865429fa0078?auto=format&fit=crop&w=500&q=60", "kg", 1);
                p.setSizes("Trái lớn, Trái vừa"); p.setStockQuantity(50); productDao.insert(p);

                p = new Product("Vú sữa Lò Rèn", "Miền Tây", "Chín cây, vỏ mỏng, nước trắng như sữa, ngọt lịm.", 65000, "https://images.unsplash.com/photo-1528821128474-27f963b062bf?auto=format&fit=crop&w=500&q=60", "kg", 1);
                p.setSizes("Size tiêu chuẩn"); p.setStockQuantity(30); productDao.insert(p);

                p = new Product("Bưởi Da Xanh", "Bến Tre", "Ruột hồng, không hạt, mọng nước, vị ngọt đậm.", 95000, "data:image/jpeg;base64,", "trái", 1);
                p.setSizes("1.2kg-1.5kg"); p.setStockQuantity(20); productDao.insert(p);

                // Nhập khẩu (Cat 2)
                p = new Product("Táo Envy Mỹ", "USA", "Giòn đanh, vị ngọt đậm, hương thơm sang trọng.", 155000, "https://images.unsplash.com/photo-1560806887-1e4cd0b6bcd6?auto=format&fit=crop&w=500&q=60", "kg", 2);
                p.setOriginalPrice(185000); p.setSizes("Size 24, Size 30"); p.setStockQuantity(25); productDao.insert(p);

                p = new Product("Nho Mẫu Đơn", "Japan", "Shine Muscat, không hạt, thơm hương hoa.", 850000, "data:image/jpeg;base64,", "chùm", 2);
                p.setSizes("Chùm 500g"); p.setStockQuantity(10); productDao.insert(p);

                p = new Product("Kiwi Vàng Zespri", "New Zealand", "Vị ngọt mát, giàu vitamin, vỏ mỏng mịn.", 195000, "data:image/jpeg;base64,", "kg", 2);
                p.setSizes("Hộp 1kg"); p.setStockQuantity(40); productDao.insert(p);

                // Sấy (Cat 3)
                p = new Product("Mít Sấy Giòn", "Vinamit", "Sấy tự nhiên, không đường, giòn tan.", 120000, "https://images.pexels.com/photos/6316531/pexels-photo-6316531.jpeg?auto=compress&cs=tinysrgb&w=500", "gói", 3);
                p.setSizes("Gói 250g"); p.setStockQuantity(60); productDao.insert(p);

                p = new Product("Xoài Sấy Dẻo", "Nông Lâm", "Vị chua ngọt, dẻo mềm tự nhiên.", 75000, "https://images.pexels.com/photos/5945848/pexels-photo-5945848.jpeg?auto=compress&cs=tinysrgb&w=500", "gói", 3);
                p.setSizes("Gói 100g"); p.setStockQuantity(100); productDao.insert(p);

                // Nước ép (Cat 4)
                p = new Product("Nước Ép Cam", "FruitApp", "Nguyên chất vắt trong ngày, không đường.", 45000, "https://images.unsplash.com/photo-1613478223719-2ab802602423?auto=format&fit=crop&w=500&q=60", "chai", 4);
                p.setSizes("330ml, 500ml"); p.setStockQuantity(20); productDao.insert(p);

                // Giỏ quà (Cat 5)
                p = new Product("Giỏ Quà Trái Cây", "FruitApp", "Kết hợp Táo Envy, Nho Mỹ và Cam Úc.", 850000, "data:image/jpeg;base64,", "giỏ", 5);
                p.setOriginalPrice(950000); p.setSizes("Tiêu chuẩn"); p.setStockQuantity(5); productDao.insert(p);

                // === 3. Seed Users & Reviews ===
                UserDao userDao = database.userDao();
                userDao.insert(new User("admin", "123456", "Quản trị viên", "0900000000"));

                ReviewDao reviewDao = database.reviewDao();
                reviewDao.insert(new Review(1, 1, 5.0f, "Xoài rất ngọt!", "20/03/2025", "Văn A"));
                reviewDao.insert(new Review(1, 4, 5.0f, "Táo giòn, rất tươi.", "21/03/2025", "Thị B"));

                // Sync ratings
                for (Product prod : productDao.getAllProducts()) {
                    float avg = reviewDao.getAverageRating(prod.getId());
                    int count = reviewDao.getReviewCount(prod.getId());
                    prod.setRating(count > 0 ? avg : 5.0f); // Default 5.0 for seeding
                    prod.setReviewCount(count > 0 ? count : 1);
                    productDao.update(prod);
                }
            });
        }
    }
}
